  function gearStats(){let total={hp:0,damage:0,magnet:0,speed:0,fire:0,armor:0,loot:0,dash:0,crit:0};for(const slot of GEAR_SLOTS){let item=equippedItem(slot);if(!item)continue;for(const key of Object.keys(item.stats||{}))total[key]=(total[key]||0)+item.stats[key]}total.armor=Math.min(.35,total.armor);total.crit=Math.min(.5,total.crit);total.fire=Math.min(.45,total.fire);total.speed=Math.min(.4,total.speed);total.dash=Math.min(.45,total.dash);return total}
