  function bossRewardOptions(){let ids=currentBoss().kind==='tyrant'?TYRANT_SCHEMATIC_IDS:WARDEN_SCHEMATIC_IDS,choices=ids.filter(id=>schematicLevel(id)<BOSS_SCHEMATICS[id].max);return choices.length?choices:['dividend']}
  function lootMultiplier(nextTier){let singularity=hasSynergy('singularity')?1.18:1,salvage=1+Math.min(.6,save.salvage*.035),gear=1+gearStats().loot,recycler=1+schematicLevel('recycler')*.05,routeBonus=routeConfig()?routeConfig().scrap:1;return (1+(depth-1)*.11)*(1+(nextTier==null?riskTier:nextTier)*.32)*salvage*gear*singularity*recycler*routeBonus}
  function lootGlyph(item){return GEAR_SLOT_META[item.slot]?GEAR_SLOT_META[item.slot].icon:'\u2726'}
  function formatGearStats(item){let s=item&&item.stats||{},parts=[];if(s.hp)parts.push('+'+s.hp+' HP');if(s.damage)parts.push('+'+s.damage+' DMG');if(s.magnet)parts.push('+'+s.magnet+' REACH');if(s.speed)parts.push('+'+Math.round(s.speed*100)+'% MOVE');if(s.fire)parts.push('+'+Math.round(s.fire*100)+'% STRIKE');if(s.armor)parts.push('+'+Math.round(s.armor*100)+'% ARMOR');if(s.loot)parts.push('+'+Math.round(s.loot*100)+'% VALUE');if(s.dash)parts.push('-'+Math.round(s.dash*100)+'% DASH');if(s.crit)parts.push('+'+Math.round(s.crit*100)+'% CRIT');return parts}
  function lootRarityRoll(elite,minimum){
    let routeBonus=routeConfig()?routeConfig().lootRare:0,r=Math.random(),legendary=.0008+(depth-1)*.00008+riskTier*.00018+(elite?.0012:0)+routeBonus*.004,mythic=.008+(depth-1)*.0015+riskTier*.002+(elite?.02:0)+routeBonus*.04,epic=.045+(depth-1)*.008+riskTier*.012+(elite?.05:0)+routeBonus*.15,rare=.19+(depth-1)*.018+riskTier*.03+(elite?.1:0)+routeBonus,rarity=r<legendary?'legendary':r<legendary+mythic?'mythic':r<legendary+mythic+epic?'epic':r<legendary+mythic+epic+rare?'rare':'common';
    if(minimum&&LOOT_RARITIES[rarity].rank<LOOT_RARITIES[minimum].rank)rarity=minimum;return rarity
  }
  function rollLootItem(elite,minimum,forcedId){if(forcedId&&LOOT_BY_ID[forcedId])return LOOT_BY_ID[forcedId];let rarity=lootRarityRoll(elite,minimum),pool=LOOT_BY_RARITY[rarity];return pool[Math.floor(Math.random()*pool.length)]}
  function lootManifest(){return Object.values(lootBag).sort((a,b)=>LOOT_RARITIES[LOOT_BY_ID[b.id].rarity].rank-LOOT_RARITIES[LOOT_BY_ID[a.id].rarity].rank||b.value-a.value)}
