    for(const e of enemies){if(e.dead)continue;e.anim=(e.anim||0)+dt;e.hit=Math.max(0,e.hit-dt);e.attack=Math.max(0,e.attack-dt);e.fire-=dt;let dx=player.x-e.x,dy=player.y-e.y,l=Math.hypot(dx,dy)||1,nx=dx/l,ny=dy/l;e.angle=Math.atan2(dy,dx);if(e.boss){let stage=e.bossStage||1,tyrant=e.bossKind==='tyrant',desired=tyrant?(stage===1?270:stage===2?235:205):(stage===1?295:stage===2?255:220),approach=l>desired+35?1:l<desired-45?-1:0,orbit=tyrant?(stage===3?.48:stage===2?.34:.22):(stage===3?.72:stage===2?.56:.4);e.x+=(nx*approach-ny*orbit)*e.speed*dt;e.y+=(ny*approach+nx*orbit)*e.speed*dt;if(e.charge>0){e.charge-=dt;if(e.charge<=0)bossVolley(e,nx,ny)}else if(e.fire<=0){e.charge=tyrant?(stage===1?.78:stage===2?.72:.55):(stage===1?.72:stage===2?.88:.58);e.fire=tyrant?(stage===1?2.05:stage===2?1.82:1.48):(stage===1?2.15:stage===2?1.9:1.55)}}else if(e.type==='shooter'){let approach=l>315?1:l<205?-1:0;e.x+=(nx*approach-ny*.48*e.strafe)*e.speed*dt;e.y+=(ny*approach+nx*.48*e.strafe)*e.speed*dt;if(e.charge>0){e.charge-=dt;if(e.charge<=0)shootEnemy(e,nx,ny)}else if(e.fire<=0){e.charge=.48;e.fire=Math.max(.9,2.25-depth*.05-riskTier*.07)}}else if(e.type==='lancer'){if(e.dashTime>0){e.dashTime-=dt;e.x+=e.dashX*430*dt;e.y+=e.dashY*430*dt}else{let approach=l>270?1:l<180?-1:0;e.x+=(nx*approach-ny*.65*e.strafe)*e.speed*dt;e.y+=(ny*approach+nx*.65*e.strafe)*e.speed*dt;if(e.charge>0){e.charge-=dt;if(e.charge<=0){e.dashTime=.34;e.dashX=nx;e.dashY=ny;effects.push({x:e.x,y:e.y,r:4,maxR:34,life:.2,max:.2,color:'#8f9dff'})}}else if(e.fire<=0){e.charge=.62;e.fire=2.1-riskTier*.08}}}else{e.x+=nx*e.speed*dt;e.y+=ny*e.speed*dt}if(l<e.r+player.r+3&&e.attack<=0){e.attack=.72;if(damagePlayer(e.damage))return}}enemies=enemies.filter(e=>!e.dead);
